INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Similitude', 'Principio fundamental da homeopatia: uma substancia capaz de provocar sintomas em individuos saudaveis pode curar sintomas semelhantes em individuos doentes, em doses infinitesimais.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Dinamizacao', 'Processo farmacotecnico homeopatico: diluicao sucessiva acompanhada de agitacao vigorosa (sucussao) para potencializar a acao medicamentosa.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Potencia', 'Grau de dinamizacao de um medicamento homeopatico, indicando quantas vezes a substancia foi diluida e sucussionada.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Tintura-mae', 'Preparacao hidroalcoolica obtida por maceracao de substancias vegetais, animais ou minerais, ponto de partida para medicamentos homeopaticos.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Nosodio', 'Medicamento homeopatico preparado a partir de produtos patologicos, como secrecoes morbidas ou culturas microbianas, diluidos e dinamizados.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Miasma', 'Predisposicao morbida subjacente as doencas cronicas. Os tres miasmas classicos sao a psora, a sicose e o luetismo.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Psora', 'Primeiro miasma homeopatico: predisposicao a disturbios funcionais sem lesao estrutural, com manifestacoes cutaneas e periodicidade.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Sicose', 'Segundo miasma homeopatico: tendencia a hiperplasia e hipertrofia tecidual, com formacao de verrugas e condilomas.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Luetismo', 'Terceiro miasma homeopatico: tendencia a destruicao tecidual com formacao de ulceras e fistulas.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Simillimum', 'O medicamento homeopatico cuja patogenesia melhor corresponde a totalidade dos sintomas do paciente.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Patogenesia', 'Conjunto de sinais e sintomas observados durante a experimentacao de uma substancia em individuos saudaveis.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Repertorizacao', 'Metodo de pesquisa do medicamento homeopatico: buscar no repertorio os sintomas do paciente para encontrar o simillimum.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Forca Vital', 'Energia sutil responsavel por manter o equilibrio e o funcionamento harmonico do organismo.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Sucussao', 'Serie de agitacoes vigorosas realizadas a cada etapa de diluicao do medicamento homeopatico.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Individualizacao', 'Principio segundo o qual cada paciente deve ser tratado de forma unica, considerando sintomas fisicos, emocionais e mentais.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Totalidade Sintomatica', 'Conjunto completo de sinais e sintomas que deve ser considerado na escolha do medicamento homeopatico.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Modalidade', 'Circunstancia que agrava ou melhora um sintoma: horario, temperatura, posicao, movimento, alimentacao ou clima.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Agravacao Homeopatica', 'Intensificacao temporaria dos sintomas apos administracao do medicamento correto, sinal positivo de reacao curativa.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Organon', 'Obra fundamental da homeopatia escrita por Samuel Hahnemann que estabelece os principios da pratica homeopatica.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Escala Centesimal (CH)', 'Escala de diluicao na proporcao de 1:100 a cada dinamizacao, seguida de sucussao.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Escala Decimal (DH)', 'Escala de diluicao na proporcao de 1:10 a cada dinamizacao, seguida de sucussao.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Escala LM', 'Escala cinquenta-milesimal com proporcao de 1:50.000 a cada dinamizacao. Menor risco de agravacao.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Dose Unica', 'Forma de prescricao na qual o medicamento e administrado uma unica vez, aguardando-se a resposta do organismo.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Cefaleia', 'Dor de cabeca de intensidade e localizacao variaveis, classificada como primaria (enxaqueca, tensional) ou secundaria.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Dispneia', 'Dificuldade respiratoria ou sensacao subjetiva de falta de ar.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Astenia', 'Estado de fraqueza generalizada, cansaco fisico e falta de energia.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Pirexia', 'Elevacao da temperatura corporal acima dos valores normais (febre).');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Edema', 'Acumulo anormal de liquido nos tecidos intersticiais, resultando em inchaco.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Pirose', 'Sensacao de queimacao retroesternal (azia), geralmente associada ao refluxo gastroesofagico.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Prurido', 'Sensacao cutanea de coceira, de origem dermatologica, sistemica ou psicogenica.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Epistaxe', 'Sangramento nasal, geralmente originado na regiao anterior do septo nasal.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Disuria', 'Dificuldade ou dor ao urinar, associada a infeccoes do trato urinario.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Taquicardia', 'Aumento da frequencia cardiaca acima de 100 bpm em adultos.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Bradicardia', 'Diminuicao da frequencia cardiaca abaixo de 60 bpm em adultos.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Artralgia', 'Dor articular sem sinais inflamatorios evidentes.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Mialgia', 'Dor muscular de intensidade variavel, localizada ou difusa.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Lombalgia', 'Dor na regiao lombar (parte inferior das costas).');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Vertigem', 'Sensacao ilusoria de movimento rotatorio, geralmente de origem vestibular.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Parestesia', 'Sensacao anormal de formigamento ou dormencia na pele.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Epigastrio', 'Regiao central e superior do abdome, sobre a qual se projetam o estomago e parte do pancreas.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Hipocondrio', 'Regioes laterais superiores do abdome, abaixo das ultimas costelas (figado e baco).');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Vertex', 'Ponto mais elevado do cranio, no topo da cabeca.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Anamnese', 'Entrevista clinica detalhada para coleta de informacoes sobre a historia da doenca, antecedentes e habitos.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Anamnese Homeopatica', 'Avaliacao integral do paciente investigando aspectos fisicos, emocionais, mentais e constitucionais.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Auscultacao', 'Tecnica de exame fisico usando estetoscopio para ouvir sons dos orgaos internos.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Palpacao', 'Tecnica de exame fisico usando as maos para avaliar temperatura, textura, forma e sensibilidade.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Percussao', 'Tecnica de exame fisico que produz sons para avaliar estruturas subjacentes.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Semiologia', 'Area da medicina dedicada ao estudo dos sinais e sintomas das doencas.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Constitucional', 'Medicamento homeopatico selecionado com base no conjunto total de caracteristicas do paciente.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Materia Medica', 'Obra que reune dados das patogenesias, instrumento fundamental para prescricao homeopatica.');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Aborto', 'ABORTOPara evitar o aborto:  capim pé de galinha  calêndula  espelina  lágrimas de nossa senhora (farinha)  cura tombo  unha de gato (cipó e folhas)  viburno  Plantas que podem provocar o aborto, cuidado se tomadas em quantidade:  abútua  artemisia  algodoeiro (semente)  açafrão  alecrim do jardim  arruda  babosa  buchinha do norte  aroeira  ananás (verde)  cabacinha (fruto)  café (folhas)  carurú de cachos (sementes)  cavalinha  corticeira (semente)  cipó mil homens  mamoeiro veremel');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Abscesso', 'ABSCESSOBálsamo  Papoula mexicana  Proeza japonesa  açoita cavalo - casca  assa peixe  bardana  cabeça de porongo  calêndula  cardo santo  cebola  cinamomo - folhas  erva de passarinho - fruto com farinha  jurubeba - folhas e frutos  aipo com mel e farinha - emplastro  arrebenta cavalo - aplicar o fruto  copo de leite - bulbo amassado  vassourinha do campo - folhas pisadas com sal uso externo  Ë');
