INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Adstringentes', 'ADSTRINGENTESContraem as mucosas e tecidos  açoita cavalo  álamo  begônia  bolsa de pastor  caqui  chorão  cambuí  casca de anta  casca de cedro  cipó escada  guabiroba  goiabeira  marmeleiro  nogueira  romã  rosa  sempre viva  videira (folhas)  :');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Afrodis', 'AFRODISÍACOervas que estimulam as forças sexuais geradoras e combatem a impotência sexual.  abacate  agrião  amendoim  anis  aveia  batata doce  baunilha (vagem)  caju  canela  catuaba  cereais (gérmes)  chuchuá  chicória  cipó cravo  cravo da índia  crista de galo (semente com leite ou chá das flores)  coca  calorau  damiana  erva moura (brotos novos)  gergelim  girassol (semenete)  giesta das canárias  ginseng  losna  maripuama  manjerona  mastruço  mostarda  melão de são caetano (s');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Aftas', 'AFTASPequenas bolhas ou feridas na mucosa da boca.  amora preta  amora vermelha (chá para fazer bochechos)  tansagem (bochechos)  guaçatonga (tomar e fazer bochechos)  malva  1');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Aids', 'AIDSÉ uma doença grave que se caracteriza por falta de imunidade orgânica. Ela é o fruto de um estilo de vida errado, e só é possível curar através de tratamentos naturais, já que as drogas químicas não conseguem levantar a imunidade , mas sim são imunodepressoras.  A AIDS ou SIDA é uma doença como outras e não é o HIV que a faz, mas ele é apenas consequência , é ocasional e oportunista.  Primeiro aparecem os sintomas da AIDS em algumas pessoas que apresentam a deficiência imunitária,');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Alcoolismo', 'ALCOOLISMOPlantas que ajudam a combater o vício:  angélica  carvalho (chá das bolotas)  limão  maracujá açu  couve (talos colocados na cachaça 1 colher por dia)  erva cancrosa  espinho de carneiro (a raiz no chimarrão)  flor do pará  Dar ao embriagado uma chícara d ecafé salgado.  vassoura do campo (dos brotos tomar o chá)  ');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Aleitamento', 'ALEITAMENTOPlantas que aumentam o leite materno:  abóbora (comer)  agrião  amendoim  amêndoas  aveia  banana  beldroega (comer e tomar chá)  castanha  caju  canjica  cebola  cenoura (semente)  cominho  coco  erva doce  funcho  feijão  figos  grandiuva (chá)  lentilha (comer)  milho verde  oliva (óleo)  pamonha    Plantas que diminuem ou suprimem o leite materno:  cana do brejo (chá da raiz)  cerefólio (aplicando cataplasma sobre os seios)  dulcamara (cataplasma)  escolopendra (CHÁ DE');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Alergias', 'ALERGIASGrande sensibilidade natural a determinadas substâncias. É importante descobrir a causa.  calêndula (tomar o chá das folhas ou flor), boa para qualquer alergia.    carobinha do campo contra alergia de pele tomar o chá e lavar-se com um cozimento mais forte    oficial de sala ou paina de sapo - lavar-se  tomar sal do mar em pequenas colheradas  evitar alimentos e bebidas ácidas');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Amebas', 'AMEBASSão vermes que vivem em nosso organismo, nos intestinos. Causam cólicas crônicas e disenterias.  carobinha do campo (chá das folhas em infusão)  cebola  erva de santa maria (chá)  o cozimento da raiz da ipecacuanha é empregada na cura da disenteria amebiana.  ë');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Amenorr', 'AMENORRÉIAÉ a supressão da menstruação fora da menopausa, ausência de menstruação.  aipo (chá)  arruda (chá fraco)  artemísia  avenca  baunilha  calêndula  cabeça de negro (taiuá)  carapiá  salsa de horta  margarida  marroio branco  ');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Amigdalite', 'AMIGDALITEInflamação das amígdalas, função defensora do organismo. Fazer gargarejos quentes com chá de plantas.  Angico (casca)  anis  amoreira (folhas)  alho (com leite quente)  bardana  camomila  canela  carapiá (gargarejos)  chicória  cipó chumbo  hortelã  jequitibá  limão (suco)  malva  picão  romã (folhas ou casca)  rosas (folhas ou flor)  sabugueiro  salva  tansagem (todo o pé)  trevo cheiroso  n');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Analg', 'ANALGÉSICOSacalmam o sofrimento, a dor.  açoita cavalo (chá)  alface (chá da raiz ou folha)  arnica do mato  beladona (chá fraco ou compressas)  beijo (chá)  caruru bravo (chá)  chorão (chá)  coerana (chá e compressas)  erva cidreira (chá)  erva lanceta (chá da raiz)  fruta do lobo (chá)  guiné (chá da raiz ou compressas)  espinheira santa (chá)  hortelã (uso interno e externo)  juá (chá)  jasmim do mato   malva  guaxuma  lingua d evaca (compressas)  maracujá  mulungu (chá)  pariparob');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Anemia', 'ANEMIAÉ causada por deficiência de minerais : ferro, cobre, vitaminas e proteínas. Sangue farco, pobre em glóbulos vermelhos. Ajudam a combater e evitar a anemia:  agrião  alfafa  angélica  arruta (fécula)  araticum (banhos)  arruda  aroeira (chá)  artemísia  aveia  avenca  beterraba  cabriuva  camboatá  cambuí  canela  carqueja  capim cheiro  capim de burro  canjerana  caqui  carapiá  casca de anta  catuaba  cereais em geral  centeio (sopa)  cenoura  cipó cravo (casca)  coca  coco  c');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Angina', 'ANGINAInflamação forte das mucosas da garganta, laringe e traquéia.  agrião  alho  camomila  cereja (brasileira)  cactus (chá)  cipó chumbo  erva de santa maria (folhas)  erva levante  gervão  limão (bochechos)  jequitibá (casca para gargarejos)  pariparoba (chá)  poaia preta  perpétua  poejo  mastruço  musgo da islândia  sálvia cidreira (chá)  sabugueiro  tansagem (tomar e fazer gargarejos)  tinhorão (raiz para gargarejos)  trapoeiraba (tomar e fazer gargarejos)  tomate (chá para gar');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Angina Pectoris', 'ANGINA PECTORISDoença das artérias do coração. Sintomas : forte dor no peito, falta de ar, dor que se espalha para o braços esquerdo e para as costas.  erva de santana  sete sangrias  erva de bugre  flor da noite (chá)  cacto  cordão de farde (chá)  pixirica (chá)  jaracatiá (chá)  ô');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Antibi', 'ANTIBIÓTICOUm grande número de plantas apresentam pricípios ativos antimicrobianos.  alho  alamanda  ciolácea  bardana (o pó da raiz contra furúnculos)  ipê roxo  jacararandá  tansagem  salsaparrilha  taiuiá  algas marinhas  guaiaco  caroba  m');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Anticoncepcionais', 'ANTICONCEPCIONAISPlantas que influem oara evitar a concepção:  aipo (chá)  agnoscasto (chá)  alecrim (chá forte)  algodoeiro (chá)  alfavaca  aspargo  bambu (raiz)  caaheê  erva de passarinho  eucalipto  fumo  funcho  golfões (branco e amarelo)  hissopo  manjericão  mentrasto  mimo de vênus  nogueira (folhas e casca)  sálvia  urtiga  urtigão  estévia  verbena  $');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Ant', 'ANTÍDOTOSPlantas que influem oara evitar a concepção:  aipo (chá)  agnoscasto (chá)  alecrim (chá forte)  algodoeiro (chá)  alfavaca  aspargo  bambu (raiz)  significa contravenenos:  chapéu de couro  cipó mil homens/espelina  fedegoso  colorau (sementes)  guaçatonga (suco da casca aplicar e tomar)  limoeiro  sassafrás  maria mole (faz e suar eliminar as toxinas)  terra virgem  O calcário entre os nós das hastes do bambu comum é um contraveneno universal. São antídotos todas as plantas');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Apendicite', 'APENDICITEConsultar o médico, não esperar. Para aliviar a dor, aplicar cataplasma de leite coalhado ou colocar gelo sobre o baixo ventre. Se for crônica:  alfafa (chá)  beladona  cipó mil homens  cipósuma  guaxuma (raiz)  picão (raiz)  tansagem (chá)  m');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Aperiente', 'APERIENTEAbem o apetite.  Chá de :   alecrim  alfazema  arruda  anis  avenca  cambuí  casca de anta  cipó cravo  cipó mil homens  cordão de frade  dente de leão  funcho  gervão  hortelã  gengibre  jatobá  limão  losna  quebra pedra  quebra tudo  paratudo  pau amargo  salsa  tinguaciba  vinagreira  A vitamina C favorece o apetite. Tomam-se antes das refeições.  v');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Arteriosclerose', 'ARTERIOSCLEROSEDegeneração e endurecimento das artérias, capilares .  Plantas recomendadas em forma de chá:  alcachofra  alface  alho  amora branca  cana de macaco  cebola  chapéu de couro  chá de bugre  guaraná  espinheira alvar  jurubeba  limão  maçã (vinagre ou chá das cascas da fruta)  oliveira (chá)  sete sangria  sabugueiro  taiuiá  visco ou erva de passarinho    5');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Artrite', 'ARTRITEInflamação nas articulações.  Tomar durante o dia duas xícaras de chá de cavalinha e 4 xícaras de chá de aipo.  urtiga  raçá  alfafa  barbasco  buva  calêndula  alfavaca  carobinha  cedro rosa  coerana (a raiz)  guiné  guaco  cerejeira  salsaparrilha  malvão  violeta  aplicar compressas quentes.    ý');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Artrose', 'ARTROSEafecção não inflamatória degenerativa de uma articulação. Tomar chá de :  aipo  alfafa  araçá  buva  calêndula  cedro rosa  caroba (casca)  canema (raiz)  guiné  guaco  paineira (casca)  salsaparrilha  tarumã  rabanete  violeta  cavalinha      Õ');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Asma', 'ASMAcombatem a asma, dificuladde de respirar:  agoniada  alfazema  azedinha (hortaliça)  bananeira (suco)  beladona (folhas, fumar as flores0  cambará  cambui  cardo santo  cará de pedra  cedro vermelho (flores)  celidônia  cenoura (bulbo)  cerefólio  cordão de frade  corticeira (casca)  dorme dorme (xarope)  embaúba (raiz)  espinheiro maricá (folhas)  eucalipto (folhas)  figo (fruto)  gengibre (bulbo)  hortelã brava  jabuticaba (entrecasca)  limão  mamoeiro (flor)  marroio  maracujá');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Azia', 'AZIAVer estômago. Plantas indicadas:  agrião  alecrim  arruda  artemísia  aspargo  boldo do chile  bardana  cancrosa  carqueja  canela  catinga de mulata  cipó mil homens  dente de leão  erva macaé  erva tostão  espinheira santa  hortelã  gervão  gengibre  juá  jurubeba  losna  limão  moranguinho  mamangava  marcela  mamica de cadela (casca)  pau amargo  pariparoba  picão  poejo  pita  quina  quebra pedra  rúcula  salsa  sucupira (semente)  zínia  ');
