INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Celulite', 'CELULITEé uma alteração do tecido celular subcutâneo. exercícios físicos, massagens para favorecer a circulação. mudar hábitos alimentares, aplicar argila com erva hera-terrestre.  usar chá de ervas como:  cabelo de milho  cavalinha  dente de leão  taquara (folhas)  sabugueiro  cataplasma com farelo , de algas, de coalhada.  evitar descontroles hormonais.b');
