INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Colesterol', 'COLESTEROLtaxa nprmal 200 mg%; suspeito 220 a 260; alta 260 a mais  taxa dos triglicerídios: normal 150 mg; suspeito 150-200; alta 200 a mais.  ajudam a combater:  alcachofra  alecrim  camomila  alho  chapéu de couro  melissa  menta  pata de vaca  salva  chucrute  vinagre de maçã (3 colheres de sopa por dia)  seguir regime alimentar, fazer jejum peródico.  usar chás laxantes e diuréticos. evitar abuso de gorduras, farinhas e açúcar.!');
INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Coluna Vertebral', 'COLUNA VERTEBRALaliviar dores:  falso boldo  maria mole (aquecer e aplicar)  beladona (folhas aplicar)  hortênsia (folhas aplicar)  corticeira (com o cozimento fazer compressas)  couve (folhas aplicar)    Tomar chá de :  açoita cavalo  arnica  alfafa  batata purga  aveia  caroba  cipó mil homens  louro  losna  pacová  feijão (folhas cataplasma)  perobinha  manjerona  sarsaparrilha  urtiga      Ê');
