INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Pomadas', 'POMADASconhecendo-se as propriedades de uma planta , com a qual se faz pomada, sabe-se em que doença aplicar. entre muitas ervas que o povo usa para fazer pomadas, temos as seguintes plantas:  alho   aroeira  arruda  araticum  angico  araruta  artemísia - folhas e flores  arnica  babosa  banana - fruta  barba d epau  bardana  beladona  buva  calêndula  chá de bugre  capuchinha  cancerosa  canforeira  catinga de mulata  caroba  cebola  cinamomo  cipreste  cipó imbé  confrei  copo de le');
