INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Raquitismo', 'RAQUITISMOplantas que combatem:  alfafa  agrião  alcachofra  cominho  confrei - folhas  manjerona  jatobá - seiva  limão  rábano  salvia  nogueira - crianças dar banho da infusão  é carência muitas vezes de vitamina D cálcio fosforado, alimentação defeituosa  aconselha-s a expor o corpo aos raios do sol pela manhã, raios ultravioletas que ajudam a formar a vitamina D  tomar uma ou duas gemas de ovo em leite com água.  veja ANEMIA)');
