INSERT INTO "MedicalDictionary" (id, term, definition) VALUES (gen_random_uuid()::text, 'Rosto', 'ROSTOcom sardas:  agrião - banhar o rosto com o suco com vinagre  celidônia - chá  limão - passar  cipó suma - chá  maravilha - passar o suco das flores ou pó da semente com suco de limão  trapoeraba - passar o suco fresco  canafístula - aplicar o suco verde das folhas com clara de ovo  pepino - suco do mesmo  feijão branco - por os grãos de molho em vinagre até poder descansar, secar, reduzir a pó e misturar com azeite e aplicar  veja ACNE');
